                                            <span className="text-xs text-gray-500">
                                                {new Date(user.createdAt || Date.now()).toLocaleDateString()}
                                            </span>
                                        </div>
                                        <p className="text-sm text-gray-600">
                                            {user.firstName} {user.lastName} ({user.email}) awaiting approval
                                        </p>
